-- ----------------------------------------------------------------------------
-- Projects: Table: Projects
-- ----------------------------------------------------------------------------
CREATE TABLE projects (
  project_id                          TEXT                 PRIMARY KEY,
  name                                TEXT                ,
  description                         TEXT                ,
  project_type                        TEXT                ,
  due_date                            TIMESTAMPTZ         ,
  is_approved                         BOOLEAN             ,
  approved_by                         TEXT                
);
COMMENT ON TABLE projects IS 'Table: Projects';

-- ----------------------------------------------------------------------------
-- Employees: Table: Employees
-- ----------------------------------------------------------------------------
CREATE TABLE employees (
  employee_id                         TEXT                 PRIMARY KEY,
  name                                TEXT                ,
  email_address                       TEXT                ,
  phone_number                        TEXT                ,
  role                                TEXT                ,
  projects                            TEXT                
);
COMMENT ON TABLE employees IS 'Table: Employees';

-- ----------------------------------------------------------------------------
-- Roles: Table: Roles
-- ----------------------------------------------------------------------------
CREATE TABLE roles (
  role_id                             TEXT                 PRIMARY KEY,
  name                                TEXT                ,
